ST.xhtml:
CASE nState OF
    0: // IDLE
        IF bIn <> bLast THEN
            nState := 10;
        END_IF
    10: // SETTLING
        bLast := bIn;
        bOut := bIn;
        nState := 0;
END_CASE

CASE nState OF
    0: // IDLE
        bDone := FALSE;
        IF bStart THEN
            nState := 10;
        END_IF
    10: // TIMING
        bDone := TRUE;
        nState := 90;
    90: // DONE
        IF NOT bStart THEN
            nState := 0;
        END_IF
END_CASE

// 01: main state machine — 0 IDLE / 10-20 WORK / 90 DONE / 99 ERROR
CASE nState OF
    0: // IDLE — wait for enable + execute
        bBusy := FALSE;
        bDone := FALSE;
        IF bEnable AND bExecute THEN
            nState := 10;
        END_IF

    10: // WORK: acquire
        bBusy := TRUE;
        nCycleCount := nCycleCount + 1;
        fbSub(bIn := bEnable);
        nState := 20;

    20: (* WORK: process the sample and compute position *)
        rActPos := rSetpoint * rScale;
        lrAccum := lrAccum + LREAL#TO_LREAL(rActPos);
        fbTimer(bStart := TRUE, tDelay := tTimeout);
        IF fbTimer.bDone THEN
            nState := 90;
        END_IF

    90: // DONE — publish result, return to idle
        bDone := TRUE;
        bBusy := FALSE;
        nState := 0;

    99: // ERROR — latch fault
        bErr := TRUE;
        nErrId := 16#8001;
        bBusy := FALSE;
END_CASE

// Global reset path
IF bReset THEN
    bErr := FALSE;
    nErrId := 0;
    nState := 0;
END_IF

