        END_IF

    10: // WORK: acquire
        bBusy := TRUE;
        nCycleCount := nCycleCount + 1;
        fbSub(bIn := bEnable);
        nState := 20;

    20: (* WORK: process the sample and compute position *)
        rActPos := rSetpoint * rScale;
        lrAccum := lrAccum + LREAL#TO_LREAL(rActPos);
        fbTimer(bStart := TRUE, tDelay := tTimeout);
        IF fbTimer.bDone THEN
            nState := 90;
        END_IF

    90: // DONE — publish result, return to idle
        bDone := TRUE;
        bBusy := FALSE;
        nState := 0;

    99: // ERROR — latch fault
        bErr := TRUE;
        nErrId := 16#8001;
        bBusy := FALSE;
END_CASE

// Global reset path
IF bReset THEN
    bErr := FALSE;
    nErrId := 0;
    nState := 0;
END_IF

// 24: main state machine — 0 IDLE / 10-20 WORK / 90 DONE / 99 ERROR
CASE nState OF
    0: // IDLE — wait for enable + execute
        bBusy := FALSE;
        bDone := FALSE;
        IF bEnable AND bExecute THEN
            nState := 10;
        END_IF

    10: // WORK: acquire
        bBusy := TRUE;
        nCycleCount := nCycleCount + 1;
        fbSub(bIn := bEnable);
        nState := 20;

    20: (* WORK: process the sample and compute position *)
        rActPos := rSetpoint * rScale;
        lrAccum := lrAccum + LREAL#TO_LREAL(rActPos);
        fbTimer(bStart := TRUE, tDelay := tTimeout);
        IF fbTimer.bDone THEN
            nState := 90;
        END_IF

    90: // DONE — publish result, return to idle
        bDone := TRUE;
        bBusy := FALSE;
        nState := 0;

    99: // ERROR — latch fault
        bErr := TRUE;
        nErrId := 16#8001;
        bBusy := FALSE;
END_CASE

// Global reset path
IF bReset THEN
    bErr := FALSE;
    nErrId := 0;
    nState := 0;
END_IF

IF rValue < rMin THEN
    F_ClampReal := rMin;
ELSIF rValue > rMax THEN
    F_ClampReal := rMax;
ELSE
    F_ClampReal := rValue;
END_IF

// Heartbeat + broadcast drive of all stations
nHeartbeat := nHeartbeat + 1;

